// Helper function to find the corresponding device by slaveId and channel
function findDevice(slaveId, channel) {
  for (const devKey in devices) {
    const device = devices[devKey];
    if (device.slaveId === slaveId && device.channelId === channel) {
      return device;
    }
  }
}

// Parse device name to extract multiplier from format: "Hidr. <Name> x<multiplier> <initial>"
// e.g. "Hidr. Teta_tetinha x100 2810m3" → { actualName: "Hidr. Teta_tetinha", multiplier: 100 }
function parseMultiplier(deviceName) {
  const match = deviceName.match(/^(.*?)\s*x(\d+\.?\d*)[AV]?\s*/i);
  if (match) {
    return { multiplier: parseFloat(match[2]) };
  }
  return { multiplier: 1 };
}

const readings = Array.isArray(msg.payload) ? msg.payload : [];

// 1) AGRUPA DO JEITO ORIGINAL (chave = device.name), aplicando o multiplier
const originalMap = readings.reduce((acc, reading) => {
  const device = findDevice(reading.slave_id, reading.channel);
  if (!device) return acc;

  const { multiplier } = parseMultiplier(device.name);
  const valueToAdd = reading.value * multiplier;

  if (!(device.name in acc)) {
    acc[device.name] = [];
  }

  acc[device.name].push({
    ts: new Date(reading.timestamp).getTime(),
    values: { pulses: valueToAdd },
  });

  return acc;
}, {});

// 2) CRIA UMA CÓPIA COM NOMES "LIMPOS" (pode fundir chaves que virem iguais)
const normalizedMap = Object.entries(originalMap).reduce((out, [rawName, arr]) => {
  const cleanName = getNameWithoutMultipliers(rawName);
  if (!out[cleanName]) out[cleanName] = [];
  out[cleanName].push(...arr);
  return out;
}, {});

msg.payload = normalizedMap;
return msg;

function formatForPostgresInQuery(arrayOfArrays) {
    // Map each sub-array to a string in the format "(x, y)"
    const formattedItems = arrayOfArrays.map(subArray => 
        `(${subArray.join(', ')})`
    );

    // Join all the formatted items into one string with proper enclosing
    return `(${formattedItems.join(', ')})`;
}


